export function serializeHeaders(headers: Headers): Record<string, string> {
  const result: Record<string, string> = {};

  headers.forEach((value, key) => {
    // FIX: Forceer Content-Type naar Pascal-Case.
    // Dit zorgt dat Scaleway zijn default 'application/json' overschrijft
    // in plaats van samenvoegt.
    if (key.toLowerCase() === 'content-type') {
      result['Content-Type'] = value;
    } else {
      result[key] = value;
    }
  });

  // Speciale Set-Cookie afhandeling (zoals eerder besproken)
  if ('getSetCookie' in headers && typeof headers.getSetCookie === 'function') {
    const cookies = headers.getSetCookie();
    if (cookies.length > 0) {
      result['Set-Cookie'] = cookies.join(', '); // Ook Set-Cookie netjes met hoofdletters
    }
  }

  return result;
}
